const fs = require('fs');
let stdout;
try {
  stdout = fs.readFileSync('/config/roster.json', 'utf8');
} catch (e) {
  stdout = '{"__error":"file_not_found"}';
}
return [{ json: { stdout } }];

const raw = $input.first().json.stdout;

if (!raw || raw.trim() === '') {
  return [{ json: { valid: false, error: 'roster.json is empty', entries: [], hash: '' } }];
}

if (raw.trim() === '{"__error":"file_not_found"}') {
  return [{ json: { valid: false, error: 'roster.json not found at /config/roster.json', entries: [], hash: '' } }];
}

let data;
try {
  data = JSON.parse(raw);
} catch (e) {
  return [{ json: { valid: false, error: 'Invalid JSON: ' + e.message, entries: [], hash: '' } }];
}

const errors = [];

if (!data.team_lead || typeof data.team_lead !== 'object') {
  errors.push('Missing "team_lead" object');
} else {
  if (!data.team_lead.name) errors.push('team_lead: missing name');
  if (!data.team_lead.discord_id) errors.push('team_lead: missing discord_id');
  if (!data.team_lead.clockify_user_id) errors.push('team_lead: missing clockify_user_id');
}

if (!Array.isArray(data.developers) || data.developers.length === 0) {
  errors.push('developers: must be a non-empty array (at least 1 required)');
} else {
  data.developers.forEach((dev, i) => {
    if (!dev.name) errors.push('developers[' + i + ']: missing name');
    if (!dev.discord_id) errors.push('developers[' + i + ']: missing discord_id');
    if (!dev.clockify_user_id) errors.push('developers[' + i + ']: missing clockify_user_id');
  });
}

if (!data.client || typeof data.client !== 'object') {
  errors.push('Missing "client" object');
} else {
  if (!data.client.name) errors.push('client: missing name');
  if (!data.client.discord_id) errors.push('client: missing discord_id');
  if (!data.client.discord_channel_id) errors.push('client: missing discord_channel_id');
}

if (errors.length > 0) {
  return [{ json: { valid: false, error: errors.join(' | '), entries: [], hash: '' } }];
}

const crypto = require('crypto');
const hash = crypto.createHash('sha256').update(raw).digest('hex');

const entries = [
  {
    discord_id: data.team_lead.discord_id,
    name: data.team_lead.name,
    role: 'team_lead',
    clockify_user_id: data.team_lead.clockify_user_id,
    discord_channel_id: null
  },
  ...data.developers.map(dev => ({
    discord_id: dev.discord_id,
    name: dev.name,
    role: 'developer',
    clockify_user_id: dev.clockify_user_id,
    discord_channel_id: null
  })),
  {
    discord_id: data.client.discord_id,
    name: data.client.name,
    role: 'client',
    clockify_user_id: null,
    discord_channel_id: data.client.discord_channel_id
  }
];

return [{ json: { valid: true, entries, hash } }];

